}
  var hist = input[promptId];
  if (hist) {
    var statusStr = hist.status ? hist.status.status_str : null;
    if (statusStr === 'error') {
      erro = true;
      var msgs = hist.status.messages || [];
      for (var m of msgs) { if (m[0] === 'execution_error') { erroMsg = m[1].exception_message || 'Erro desconhecido'; break; } }
    } else if (hist.outputs) {
      var keys = Object.keys(hist.outputs);
      for (var k = 0; k < keys.length; k++) {
