var input = $('Buscar Resultado').first().json;
var staticData = $getWorkflowStaticData('global');
var promptId = staticData.vidPromptId;
staticData.vidRetries = (staticData.vidRetries || 0) + 1;
var pronto = false; var filename = null; var erro = false; var erroMsg = '';
try {
  // Detectar resposta HTML (502/erro do proxy)
var inputStr = JSON.stringify(input);
if (inputStr.includes('<!DOCTYPE') || inputStr.includes('Bad gateway')) {
  return [{ json: { _ready: false, _error: true, _errorMsg: '502 Bad Gateway - ComfyUI crashou', _timeout: false, filename: null, downloadUrl: null, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId } }];
}
  var hist = input[promptId];
  if (hist) {
    var statusStr = hist.status ? hist.status.status_str : null;
    if (statusStr === 'error') {
      erro = true;
      var msgs = hist.status.messages || [];
      for (var m of msgs) { if (m[0] === 'execution_error') { erroMsg = m[1].exception_message || 'Erro desconhecido'; break; } }
    } else if (hist.outputs) {
      var keys = Object.keys(hist.outputs);
      for (var k = 0; k < keys.length; k++) {
        var nodeOut = hist.outputs[keys[k]];
        if (nodeOut.gifs && nodeOut.gifs.length > 0) {
          filename = nodeOut.gifs[0].filename;
          pronto = true;
          break;
        }
      }
    }
  }
} catch(e) {}
var meta = $('Preparar Polling Video').first().json;
return [{ json: {
  _ready: pronto, _error: erro, _errorMsg: erroMsg,
  _timeout: (!pronto && !erro && staticData.vidRetries >= 15),
  filename: filename,
  downloadUrl: pronto ? (staticData.comfyuiUrl + '/view?filename=' + encodeURIComponent(filename) + '&type=output&subfolder=') : null,
  cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId
} }];

var msg = $('Avaliar Resultado').first().json._errorMsg || 'Erro desconhecido';
var meta = $('Avaliar Resultado').first().json;
throw new Error('❌ WAN ERRO na cena ' + meta.cenaNumero + ': ' + msg);

